/* harmony default export */ const __WEBPACK_DEFAULT_EXPORT__ = ("<div class=\"package-container\">\n    <div class=\"package-header\">\n        <div class=\"container\">\n            <h1>simple-boot-http-server-ssr</h1>\n            <p class=\"content en\">Server-Side Rendering framework for building fast, SEO-friendly web applications</p>\n            <p class=\"content ko\">빠르고 SEO 친화적인 웹 애플리케이션을 구축하기 위한 서버 사이드 렌더링 프레임워크</p>\n            <div class=\"package-actions\">\n                <a href=\"https://github.com/dooboostore-develop/packages/blob/main/@dooboostore/simple-boot-http-server-ssr\" target=\"_blank\" rel=\"noopener noreferrer\">\n                    <img src=\"https://img.shields.io/badge/Github-555555?style=flat&logo=github&logoColor=white\" alt=\"GitHub\"/>\n                </a>\n                <a href=\"https://www.npmjs.com/package/@dooboostore/simple-boot-http-server-ssr\" target=\"_blank\" rel=\"noopener noreferrer\">\n                    <img src=\"https://img.shields.io/badge/Npm-cc0000?style=flat&logo=npm&logoColor=white\" alt=\"NPM\"/>\n                </a>\n            </div>\n        </div>\n    </div>\n    <div class=\"package-content\">\n        <div class=\"container\">\n            <!-- Installation -->\n            <section class=\"section\">\n                <h2 id=\"installation\">Installation</h2>\n                <p class=\"content en\">Install the package and its dependencies:</p>\n                <p class=\"content ko\">패키지와 의존성을 설치하세요:</p>\n                \n                <code-example title=\"npm\" codeClass=\"language-bash\">npm install @dooboostore/simple-boot-http-server-ssr reflect-metadata jsdom</code-example>\n                <code-example title=\"pnpm\" codeClass=\"language-bash\">pnpm add @dooboostore/simple-boot-http-server-ssr reflect-metadata jsdom</code-example>\n                <code-example title=\"Quick Start CLI\" codeClass=\"language-bash\">npm init @dooboostore/simple-boot-http-server-ssr projectname</code-example>\n            </section>\n\n            <!-- Features -->\n            <section class=\"section\">\n                <h2 id=\"features\">Features</h2>\n                <div class=\"features-grid\">\n                    <div class=\"feature-item\">\n                        <h3>Server-Side Rendering</h3>\n                        <p class=\"content en\">Renders SPA on the server before sending to client for better SEO and performance</p>\n                        <p class=\"content ko\">더 나은 SEO와 성능을 위해 클라이언트로 보내기 전에 서버에서 SPA를 렌더링</p>\n                    </div>\n                    <div class=\"feature-item\">\n                        <h3>JSDOM Integration</h3>\n                        <p class=\"content en\">Uses jsdom to create virtual DOM environment on server for front-end code execution</p>\n                        <p class=\"content ko\">프론트엔드 코드 실행을 위해 서버에서 가상 DOM 환경을 생성하는 jsdom 사용</p>\n                    </div>\n                    <div class=\"feature-item\">\n                        <h3>Component Pooling</h3>\n                        <p class=\"content en\">Manages pool of SimpleBootFront instances for efficient concurrent SSR requests</p>\n                        <p class=\"content ko\">효율적인 동시 SSR 요청을 위한 SimpleBootFront 인스턴스 풀 관리</p>\n                    </div>\n                    <div class=\"feature-item\">\n                        <h3>Data Hydration</h3>\n                        <p class=\"content en\">Automatically serializes server data and hydrates on client, avoiding redundant API calls</p>\n                        <p class=\"content ko\">서버 데이터를 자동으로 직렬화하고 클라이언트에서 하이드레이션하여 중복 API 호출 방지</p>\n                    </div>\n                    <div class=\"feature-item\">\n                        <h3>Unified Codebase</h3>\n                        <p class=\"content en\">Share routing, services, and components between server and client</p>\n                        <p class=\"content ko\">서버와 클라이언트 간 라우팅, 서비스, 컴포넌트 공유</p>\n                    </div>\n                    <div class=\"feature-item\">\n                        <h3>Intent-based Communication</h3>\n                        <p class=\"content en\">Client-server communication using custom HTTP headers and intent publishing</p>\n                        <p class=\"content ko\">커스텀 HTTP 헤더와 인텐트 퍼블리싱을 사용한 클라이언트-서버 통신</p>\n                    </div>\n                </div>\n            </section>\n\n            <!-- How It Works -->\n            <section class=\"section\">\n                <h2 id=\"how-it-works\">How It Works</h2>\n                <p class=\"content en\">The SSR process follows these steps when handling HTML requests:</p>\n                <p class=\"content ko\">HTML 요청을 처리할 때 SSR 프로세스는 다음 단계를 따릅니다:</p>\n                \n                <div class=\"process-steps\">\n                    <div class=\"process-step\" data-step=\"1\">\n                        <h4>Request Interception</h4>\n                        <p class=\"content en\">Captures the request before serving static index.html file</p>\n                        <p class=\"content ko\">정적 index.html 파일을 제공하기 전에 요청을 캡처</p>\n                    </div>\n                    <div class=\"process-step\" data-step=\"2\">\n                        <h4>Browser Environment</h4>\n                        <p class=\"content en\">Acquires pre-initialized jsdom instance from pool acting as virtual browser</p>\n                        <p class=\"content ko\">가상 브라우저 역할을 하는 풀에서 사전 초기화된 jsdom 인스턴스 획득</p>\n                    </div>\n                    <div class=\"process-step\" data-step=\"3\">\n                        <h4>App Initialization</h4>\n                        <p class=\"content en\">Uses SimpleBootFront instance from pool and sets context to jsdom window</p>\n                        <p class=\"content ko\">풀에서 SimpleBootFront 인스턴스를 사용하고 jsdom 윈도우에 컨텍스트 설정</p>\n                    </div>\n                    <div class=\"process-step\" data-step=\"4\">\n                        <h4>Routing Execution</h4>\n                        <p class=\"content en\">Triggers front-end router within jsdom environment using request path</p>\n                        <p class=\"content ko\">요청 경로를 사용하여 jsdom 환경 내에서 프론트엔드 라우터 트리거</p>\n                    </div>\n                    <div class=\"process-step\" data-step=\"5\">\n                        <h4>Component Rendering</h4>\n                        <p class=\"content en\">Front-end components render into the virtual DOM</p>\n                        <p class=\"content ko\">프론트엔드 컴포넌트가 가상 DOM으로 렌더링</p>\n                    </div>\n                    <div class=\"process-step\" data-step=\"6\">\n                        <h4>Data Fetching</h4>\n                        <p class=\"content en\">Handles server-side data fetching with automatic serialization</p>\n                        <p class=\"content ko\">자동 직렬화를 통한 서버 사이드 데이터 페칭 처리</p>\n                    </div>\n                    <div class=\"process-step\" data-step=\"7\">\n                        <h4>DOM Serialization</h4>\n                        <p class=\"content en\">Captures outerHTML of jsdom document after rendering completion</p>\n                        <p class=\"content ko\">렌더링 완료 후 jsdom 문서의 outerHTML 캡처</p>\n                    </div>\n                    <div class=\"process-step\" data-step=\"8\">\n                        <h4>Hydration Injection</h4>\n                        <p class=\"content en\">Injects serialized data into HTML inside script tag for client hydration</p>\n                        <p class=\"content ko\">클라이언트 하이드레이션을 위해 스크립트 태그 내부 HTML에 직렬화된 데이터 주입</p>\n                    </div>\n                    <div class=\"process-step\" data-step=\"9\">\n                        <h4>Response Delivery</h4>\n                        <p class=\"content en\">Sends fully rendered HTML to client for immediate display</p>\n                        <p class=\"content ko\">즉시 표시를 위해 완전히 렌더링된 HTML을 클라이언트로 전송</p>\n                    </div>\n                </div>\n            </section>\n\n            <!-- Quick Start -->\n            <section class=\"section\">\n                <h2 id=\"quick-start\">Quick Start</h2>\n                \n                <h3 id=\"factory-setup\">Factory Setup</h3>\n                <p class=\"content en\">Create a factory for both server (SSR) and client (browser) rendering:</p>\n                <p class=\"content ko\">서버(SSR)와 클라이언트(브라우저) 렌더링을 위한 팩토리를 생성하세요:</p>\n                \n                <code-example title=\"factory.ts\" codeClass=\"language-typescript\">import { SimpleBootHttpSSRFactory, SimFrontOption, SimpleBootFront } from '@dooboostore/simple-boot-http-server-ssr';\nimport { ConstructorType } from '@dooboostore/core';\nimport { IndexRouterComponent } from './components/index.router.component';\n\n// Function to create a standard front-end option object\nexport const MakeSimFrontOption = (window: any): SimFrontOption => {\n    return new SimFrontOption(window).setUrlType('path');\n}\n\n// The factory class that creates instances of the front-end application\nclass Factory extends SimpleBootHttpSSRFactory {\n    factory(simFrontOption: SimFrontOption, using: ConstructorType<any>[] = [], domExcludes: ConstructorType<any>[] = []): Promise<SimpleBootFront> {\n        const simpleBootFront = new SimpleBootFront(IndexRouterComponent, simFrontOption);\n        // Exclude certain types from being proxied by the DOM renderer\n        simpleBootFront.domRendoerExcludeProxy.push(...domExcludes);\n        return Promise.resolve(simpleBootFront);\n    }\n}\n\nexport default new Factory();</code-example>\n\n                <h3 id=\"server-setup\">Server Setup</h3>\n                <p class=\"content en\">Configure the HTTP server with SSR and Intent filters:</p>\n                <p class=\"content ko\">SSR 및 Intent 필터로 HTTP 서버를 구성하세요:</p>\n                \n                <code-example title=\"server.ts\" codeClass=\"language-typescript\">import 'reflect-metadata';\nimport { SimpleBootHttpSSRServer } from '@dooboostore/simple-boot-http-server-ssr/SimpleBootHttpSSRServer';\nimport { HttpSSRServerOption } from '@dooboostore/simple-boot-http-server-ssr/option/HttpSSRServerOption';\nimport { SSRFilter, FactoryAndParams } from '@dooboostore/simple-boot-http-server-ssr/filters/SSRFilter';\nimport { IntentSchemeFilter } from '@dooboostore/simple-boot-http-server-ssr/filters/IntentSchemeFilter';\nimport { ResourceFilter } from '@dooboostore/simple-boot-http-server/filters/ResourceFilter';\nimport Factory, { MakeSimFrontOption } from './factory';\n\n// SSR Configuration\nconst ssrOption: FactoryAndParams = {\n    frontDistPath: './dist',\n    frontDistIndexFileName: 'index.html',\n    factorySimFrontOption: (window: any) => MakeSimFrontOption(window),\n    factory: Factory,\n    poolOption: {\n        max: 50,\n        min: 5\n    },\n    using: [], // Add your services here\n    domExcludes: [], // Add types to exclude from DOM proxy\n    ssrExcludeFilter: (rr) => {\n        // Exclude certain paths from SSR\n        const excludePatterns = [\n            /^\\/api\\/.*/,\n            /^\\/assets\\/.*/,\n            /^\\/static\\/.*/\n        ];\n        return excludePatterns.some(pattern => pattern.test(rr.reqUrl));\n    },\n    simpleBootFront: {\n        notFoundError: true\n    }\n};\n\n// Create filters\nconst ssrFilter = new SSRFilter(ssrOption);\nconst resourceFilter = new ResourceFilter('./dist', ['assets/.*', '\\.js$', '\\.css$']);\n\n// Server configuration\nconst option = new HttpSSRServerOption();\noption.listen = { port: 3000, host: 'localhost' };\noption.filters = [\n    resourceFilter,\n    ssrFilter,\n    IntentSchemeFilter\n];\n\n// Start server\nconst server = new SimpleBootHttpSSRServer(option);\nserver.run().then(() => {\n    console.log('SSR Server is running on http://localhost:3000');\n});</code-example>\n\n                <h3 id=\"data-hydration\">Data Hydration</h3>\n                <p class=\"content en\">Use decorators to automatically handle server-client data synchronization:</p>\n                <p class=\"content ko\">서버-클라이언트 데이터 동기화를 자동으로 처리하는 데코레이터를 사용하세요:</p>\n                \n                <code-example title=\"Data Hydration\" codeClass=\"language-typescript\">import { SaveAroundAfter, LoadAroundBefore } from '@dooboostore/simple-boot-http-server-ssr';\n\n@Sim\nexport class UserService {\n    \n    @SaveAroundAfter('user-data') // Save to window.server_side_data on server\n    @LoadAroundBefore('user-data') // Load from window.server_side_data on client\n    async getUserProfile(userId: string) {\n        // This method runs on server during SSR\n        // Data is automatically saved and loaded on client\n        const response = await fetch(`/api/users/${userId}`);\n        return response.json();\n    }\n}\n\n@Sim\n@Component({\n    template: `\n&lt;div&gt;\n    &lt;h2&gt;User Profile&lt;/h2&gt;\n    &lt;div dr-if=\"user\"&gt;\n        &lt;p&gt;Name: $\\{user.name\\}&lt;/p&gt;\n        &lt;p&gt;Email: $\\{user.email\\}&lt;/p&gt;\n    &lt;/div&gt;\n&lt;/div&gt;\n    `\n})\nexport class UserProfileComponent implements OnInit {\n    user?: any;\n    \n    constructor(private userService: UserService) {}\n    \n    async onInit() {\n        // On server: fetches data and saves to window.server_side_data\n        // On client: loads from window.server_side_data (no API call)\n        this.user = await this.userService.getUserProfile('123');\n    }\n}</code-example>\n            </section>\n\n            <!-- Advanced Features -->\n            <section class=\"section\">\n                <h2 id=\"advanced-features\">Advanced Features</h2>\n                \n                <h3 id=\"intent-communication\">Intent-based Communication</h3>\n                <p class=\"content en\">Enable client-server communication using custom headers and intent publishing:</p>\n                <p class=\"content ko\">커스텀 헤더와 인텐트 퍼블리싱을 사용한 클라이언트-서버 통신을 활성화하세요:</p>\n                \n                <code-example title=\"Intent-based Communication\" codeClass=\"language-typescript\">// Client-side intent request\nconst response = await fetch('/api/user-action', {\n    method: 'POST',\n    headers: {\n        'Accept': 'application/json-post+simple-boot-ssr-intent-scheme',\n        'X-Simple-Boot-Ssr-Intent-Scheme': 'UserService://updateProfile',\n        'Content-Type': 'application/json'\n    },\n    body: JSON.stringify({ name: 'John Doe', email: 'john@example.com' })\n});\n\n// Server-side intent handler\n@Sim({ scheme: 'UserService' })\nexport class UserService {\n    \n    updateProfile(intent: Intent) {\n        const userData = intent.data;\n        console.log('Updating user profile:', userData);\n        \n        // Process the update\n        return {\n            success: true,\n            message: 'Profile updated successfully',\n            data: userData\n        };\n    }\n}</code-example>\n\n                <h3 id=\"component-pooling\">Component Pooling Configuration</h3>\n                <p class=\"content en\">Configure the pool of SimpleBootFront instances for optimal performance:</p>\n                <p class=\"content ko\">최적의 성능을 위한 SimpleBootFront 인스턴스 풀을 구성하세요:</p>\n                \n                <code-example title=\"Component Pooling Configuration\" codeClass=\"language-typescript\">const ssrOption: FactoryAndParams = {\n    // ... other options\n    poolOption: {\n        max: 100,        // Maximum number of instances in pool\n        min: 10,         // Minimum number of instances to maintain\n        acquireTimeoutMillis: 30000,  // Timeout for acquiring instance\n        idleTimeoutMillis: 300000,    // Idle timeout before cleanup\n        evictionRunIntervalMillis: 60000  // Cleanup interval\n    },\n    \n    // Performance optimizations\n    using: [\n        UserService,\n        DataService,\n        // Add your services that need to be available during SSR\n    ],\n    \n    domExcludes: [\n        DatabaseConnection,\n        FileSystemService,\n        // Exclude server-only services from DOM proxy\n    ],\n    \n    // Custom SSR exclusion logic\n    ssrExcludeFilter: (rr: RequestResponse) => {\n        // Skip SSR for API routes\n        if (rr.reqUrl.startsWith('/api/')) return true;\n        \n        // Skip SSR for static assets\n        if (/\\.(js|css|png|jpg|ico)$/.test(rr.reqUrl)) return true;\n        \n        // Skip SSR for specific user agents (e.g., bots that don't need SSR)\n        const userAgent = rr.reqHeaders()['user-agent'];\n        if (userAgent?.includes('bot')) return true;\n        \n        return false;\n    }\n};\n</code-example>\n\n                <h3 id=\"error-handling\">SSR Error Handling</h3>\n                <p class=\"content en\">Handle SSR-specific errors and fallbacks:</p>\n                <p class=\"content ko\">SSR 특정 오류 및 폴백을 처리하세요:</p>\n                \n                <code-example title=\"SSR Error Handling\" codeClass=\"language-typescript\">@Sim\nexport class SSRErrorHandler {\n    \n    @ExceptionHandler({ type: SSRRenderError })\n    handleSSRError(rr: RequestResponse, error: SSRRenderError) {\n        console.error('SSR rendering failed:', error);\n        \n        // Fallback to client-side rendering\n        if (!rr.resIsDone()) {\n            rr.resStatusCode(200);\n            rr.resSetHeader('Content-Type', 'text/html');\n            \n            // Serve basic HTML that will bootstrap client-side app\n            const fallbackHtml = `\n                <!DOCTYPE html>\n                <html>\n                <head>\n                    <title>Loading...</title>\n                    <script>window.SSR_FAILED = true;</script>\n                </head>\n                <body>\n                    <div id=\"app\">Loading...</div>\n                    <script src=\"/app.js\"></script>\n                </body>\n                </html>\n            `;\n            rr.resEnd(fallbackHtml);\n        }\n    }\n}\n\n// Register in server configuration\nconst option = new HttpSSRServerOption();\noption.globalAdvice = SSRErrorHandler;</code-example>\n            </section>\n\n            <!-- Core Concepts -->\n            <section class=\"section\">\n                <h2 id=\"core-concepts\">Core Concepts</h2>\n                <div class=\"concepts-grid\">\n                    <div class=\"concept-item\">\n                        <h4>SSRFilter</h4>\n                        <p class=\"content en\">Core filter that intercepts requests and performs server-side rendering</p>\n                        <p class=\"content ko\">요청을 가로채고 서버 사이드 렌더링을 수행하는 핵심 필터</p>\n                    </div>\n                    <div class=\"concept-item\">\n                        <h4>SimpleBootHttpSSRFactory</h4>\n                        <p class=\"content en\">Factory pattern for creating and managing SimpleBootFront instances</p>\n                        <p class=\"content ko\">SimpleBootFront 인스턴스 생성 및 관리를 위한 팩토리 패턴</p>\n                    </div>\n                    <div class=\"concept-item\">\n                        <h4>Data Hydration Decorators</h4>\n                        <p class=\"content en\">@SaveAroundAfter and @LoadAroundBefore for automatic data synchronization</p>\n                        <p class=\"content ko\">자동 데이터 동기화를 위한 @SaveAroundAfter 및 @LoadAroundBefore</p>\n                    </div>\n                    <div class=\"concept-item\">\n                        <h4>IntentSchemeFilter</h4>\n                        <p class=\"content en\">Handles client-server communication through intent-based messaging</p>\n                        <p class=\"content ko\">인텐트 기반 메시징을 통한 클라이언트-서버 통신 처리</p>\n                    </div>\n                    <div class=\"concept-item\">\n                        <h4>JSDOM Virtual Environment</h4>\n                        <p class=\"content en\">Server-side DOM environment for running front-end code</p>\n                        <p class=\"content ko\">프론트엔드 코드 실행을 위한 서버 사이드 DOM 환경</p>\n                    </div>\n                    <div class=\"concept-item\">\n                        <h4>Component Pooling</h4>\n                        <p class=\"content en\">Efficient resource management through instance pooling</p>\n                        <p class=\"content ko\">인스턴스 풀링을 통한 효율적인 리소스 관리</p>\n                    </div>\n                </div>\n            </section>\n        </div>\n    </div>\n</div>");

