/* harmony default export */ const __WEBPACK_DEFAULT_EXPORT__ = ("<div class=\"package-container\">\n    <div class=\"package-header\">\n        <div class=\"container\">\n            <h1>simple-boot-http-server</h1>\n            <p class=\"content en\">Lightweight and powerful HTTP web server framework for Node.js</p>\n            <p class=\"content ko\">Node.js를 위한 경량이면서 강력한 HTTP 웹 서버 프레임워크</p>\n            <div class=\"package-actions\">\n                <a href=\"https://github.com/dooboostore-develop/packages/blob/main/@dooboostore/simple-boot-http-server\" target=\"_blank\" rel=\"noopener noreferrer\">\n                    <img src=\"https://img.shields.io/badge/Github-555555?style=flat&logo=github&logoColor=white\" alt=\"GitHub\"/>\n                </a>\n                <a href=\"https://www.npmjs.com/package/@dooboostore/simple-boot-http-server\" target=\"_blank\" rel=\"noopener noreferrer\">\n                    <img src=\"https://img.shields.io/badge/Npm-cc0000?style=flat&logo=npm&logoColor=white\" alt=\"NPM\"/>\n                </a>\n            </div>\n        </div>\n    </div>\n    <div class=\"package-content\">\n        <div class=\"container\">\n            <!-- Installation -->\n            <section class=\"section\">\n                <h2 id=\"installation\">Installation</h2>\n                <p class=\"content en\">Install the package and its dependencies:</p>\n                <p class=\"content ko\">패키지와 의존성을 설치하세요:</p>\n                \n                <code-example title=\"npm\" codeClass=\"language-bash\">npm install @dooboostore/simple-boot-http-server reflect-metadata</code-example>\n                <code-example title=\"pnpm\" codeClass=\"language-bash\">pnpm add @dooboostore/simple-boot-http-server reflect-metadata</code-example>\n                <code-example title=\"Quick Start CLI\" codeClass=\"language-bash\">npm init @dooboostore/simple-boot-http-server projectname</code-example>\n            </section>\n\n            <!-- Features -->\n            <section class=\"section\">\n                <h2 id=\"features\">Features</h2>\n                <div class=\"features-grid\">\n                    <div class=\"feature-item\">\n                        <h3>Declarative Routing</h3>\n                        <p class=\"content en\">Use decorators (@Router, @Route) to map URLs to classes and methods</p>\n                        <p class=\"content ko\">데코레이터(@Router, @Route)를 사용하여 URL을 클래스와 메서드에 매핑</p>\n                    </div>\n                    <div class=\"feature-item\">\n                        <h3>HTTP Method Mapping</h3>\n                        <p class=\"content en\">Decorators for all standard HTTP methods (@GET, @POST, @PUT, @DELETE, etc.)</p>\n                        <p class=\"content ko\">모든 표준 HTTP 메서드를 위한 데코레이터(@GET, @POST, @PUT, @DELETE 등)</p>\n                    </div>\n                    <div class=\"feature-item\">\n                        <h3>Request/Response Handling</h3>\n                        <p class=\"content en\">Unified RequestResponse object to manage HTTP transactions</p>\n                        <p class=\"content ko\">HTTP 트랜잭션을 관리하는 통합된 RequestResponse 객체</p>\n                    </div>\n                    <div class=\"feature-item\">\n                        <h3>Middleware/Filters</h3>\n                        <p class=\"content en\">Intercept requests and responses for cross-cutting concerns</p>\n                        <p class=\"content ko\">횡단 관심사를 위한 요청 및 응답 가로채기</p>\n                    </div>\n                    <div class=\"feature-item\">\n                        <h3>Global Exception Handling</h3>\n                        <p class=\"content en\">Centralized error handling using @Sim advice classes</p>\n                        <p class=\"content ko\">@Sim advice 클래스를 사용한 중앙집중식 오류 처리</p>\n                    </div>\n                    <div class=\"feature-item\">\n                        <h3>Session Management</h3>\n                        <p class=\"content en\">Built-in session management with customizable storage providers</p>\n                        <p class=\"content ko\">사용자 정의 저장소 제공자를 지원하는 내장 세션 관리</p>\n                    </div>\n                    <div class=\"feature-item\">\n                        <h3>HTTPS Support</h3>\n                        <p class=\"content en\">Configure the server to run over HTTPS and HTTP/2</p>\n                        <p class=\"content ko\">HTTPS 및 HTTP/2를 통해 실행되도록 서버 구성</p>\n                    </div>\n                    <div class=\"feature-item\">\n                        <h3>Endpoints</h3>\n                        <p class=\"content en\">Define logic for different stages of request lifecycle</p>\n                        <p class=\"content ko\">요청 생명주기의 다양한 단계에 대한 로직 정의</p>\n                    </div>\n                </div>\n            </section>\n\n            <!-- Quick Start -->\n            <section class=\"section\">\n                <h2 id=\"quick-start\">Quick Start</h2>\n                \n                <h3 id=\"basic-api\">Basic API Setup</h3>\n                <p class=\"content en\">Create a simple REST API with HTTP method decorators:</p>\n                <p class=\"content ko\">HTTP 메서드 데코레이터를 사용하여 간단한 REST API를 생성하세요:</p>\n                \n                <code-example title=\"Basic API Setup\" codeClass=\"language-typescript\">import { Sim, Router, Route, RouterModule } from '''@dooboostore/simple-boot''';\nimport {\n    GET, POST, PUT, DELETE,\n    Mimes,\n    RequestResponse,\n    ReqJsonBody\n} from '''@dooboostore/simple-boot-http-server''';\n\n@Sim\n@Router({ path: '''/api/items''' })\nexport class ItemApi {\n\n    @Route({ path: '''''' })\n    @GET({ res: { contentType: Mimes.ApplicationJson } })\n    getAllItems() {\n        // Logic to get all items\n        return [{ id: 1, name: '''Item 1''' }, { id: 2, name: '''Item 2''' }];\n    }\n\n    @Route({ path: '''/{id}''' })\n    @GET({ res: { contentType: Mimes.ApplicationJson } })\n    getItemById(routerModule: RouterModule) {\n        const itemId = routerModule.pathData?.id;\n        // Logic to get item by ID\n        return { id: itemId, name: `Item ${itemId}` };\n    }\n\n    @Route({ path: '''''' })\n    @POST({\n        req: { contentType: [Mimes.ApplicationJson] },\n        res: { status: 201, contentType: Mimes.ApplicationJson }\n    })\n    createItem(body: ReqJsonBody) {\n        console.log('''Creating new item:''', body);\n        // Logic to create a new item\n        return { success: true, id: 3, ...body };\n    }\n\n    @Route({ path: '''/{id}''' })\n    @PUT({ req: { contentType: [Mimes.ApplicationJson] } })\n    updateItem(routerModule: RouterModule, body: ReqJsonBody) {\n        const itemId = routerModule.pathData?.id;\n        console.log(`Updating item ${itemId}:`, body);\n        // Logic to update an item\n        return { success: true, id: itemId, ...body };\n    }\n\n    @Route({ path: '''/{id}''' })\n    @DELETE({ res: { status: 204 } })\n    deleteItem(routerModule: RouterModule) {\n        const itemId = routerModule.pathData?.id;\n        console.log(`Deleting item ${itemId}`);\n        // Logic to delete an item\n        // No content returned for 204\n    }\n}</code-example>\n\n                <h3 id=\"http-methods\">Available HTTP Method Decorators</h3>\n                <p class=\"content en\">All standard HTTP methods are supported:</p>\n                <p class=\"content ko\">모든 표준 HTTP 메서드가 지원됩니다:</p>\n                \n                <code-example title=\"Available HTTP Method Decorators\" codeClass=\"language-typescript\">// Available method decorators:\n@GET        // GET requests\n@POST       // POST requests  \n@PUT        // PUT requests\n@DELETE     // DELETE requests\n@PATCH      // PATCH requests\n@OPTIONS    // OPTIONS requests\n@HEAD       // HEAD requests\n@TRACE      // TRACE requests\n@CONNECT    // CONNECT requests\n@UrlMapping // Generic decorator with method parameter\n\n// Example usage\n@Route({ path: '''/users/{id}''' })\n@PATCH({ \n    req: { contentType: [Mimes.ApplicationJson] },\n    res: { contentType: Mimes.ApplicationJson }\n})\npatchUser(routerModule: RouterModule, body: ReqJsonBody) {\n    const userId = routerModule.pathData?.id;\n    // Partial update logic\n    return { success: true, updated: body };\n}</code-example>\n\n                <h3 id=\"server-setup\">Server Setup</h3>\n                <p class=\"content en\">Bootstrap your HTTP server with the framework:</p>\n                <p class=\"content ko\">프레임워크로 HTTP 서버를 부트스트랩하세요:</p>\n                \n                <code-example title=\"Server Setup\" codeClass=\"language-typescript\">import { SimpleApplication } from '''@dooboostore/simple-boot''';\nimport { SimpleBootHttpServer, HttpServerOption } from '''@dooboostore/simple-boot-http-server''';\n\n// Create your main router\n@Sim\n@Router({ \n    path: '''''', \n    route: {\n        '''/api''': ItemApi,\n        // Add more routes here\n    }\n})\nclass MainRouter {}\n\n// Configure and start the server\nconst httpOption = new HttpServerOption({\n    port: 3000,\n    host: '''localhost'''\n});\n\nconst app = new SimpleApplication({ rootRouter: MainRouter });\nconst server = new SimpleBootHttpServer(app, httpOption);\n\nserver.run().then(() => {\n    console.log('''Server is running on http://localhost:3000''');\n});</code-example>\n            </section>\n\n            <!-- Advanced Features -->\n            <section class=\"section\">\n                <h2 id=\"advanced-features\">Advanced Features</h2>\n                \n                <h3 id=\"filters\">Filters & Middleware</h3>\n                <p class=\"content en\">Intercept requests and responses for cross-cutting concerns:</p>\n                <p class=\"content ko\">횡단 관심사를 위해 요청과 응답을 가로채세요:</p>\n                \n                <code-example title=\"Filters & Middleware\" codeClass=\"language-typescript\">import { Filter, RequestResponse, SimpleBootHttpServer } from '''@dooboostore/simple-boot-http-server''';\n\nexport class LoggingFilter implements Filter {\n    async before(rr: RequestResponse, app: SimpleBootHttpServer): Promise<boolean> {\n        console.log(`[${new Date().toISOString()}] ${rr.reqMethod()} ${rr.reqUrl}`);\n        return true; // Continue the chain\n    }\n\n    async after(rr: RequestResponse, app: SimpleBootHttpServer, sw: boolean): Promise<boolean> {\n        console.log(`Request finished with status ${rr.resStatusCode()}`);\n        return true;\n    }\n}\n\n// CORS Filter example\nexport class CorsFilter implements Filter {\n    async before(rr: RequestResponse, app: SimpleBootHttpServer): Promise<boolean> {\n        rr.resSetHeader('''Access-Control-Allow-Origin''', '''*''');\n        rr.resSetHeader('''Access-Control-Allow-Methods''', '''GET, POST, PUT, DELETE, OPTIONS''');\n        rr.resSetHeader('''Access-Control-Allow-Headers''', '''Content-Type, Authorization''');\n        \n        if (rr.reqMethod() === '''OPTIONS''') {\n            rr.resStatusCode(200).resEnd();\n            return false; // Stop the chain for preflight requests\n        }\n        return true;\n    }\n}\n\n// Register filters in HttpServerOption\nconst option = new HttpServerOption({\n    filters: [LoggingFilter, CorsFilter]\n});</code-example>\n\n                <h3 id=\"exception-handling\">Global Exception Handling</h3>\n                <p class=\"content en\">Handle errors globally with advice classes:</p>\n                <p class=\"content ko\">advice 클래스로 전역적으로 오류를 처리하세요:</p>\n                \n                <code-example title=\"Global Exception Handling\" codeClass=\"language-typescript\">import { Sim, ExceptionHandler, Inject, ExceptionHandlerSituationType } from '''@dooboostore/simple-boot''';\nimport { RequestResponse, NotFoundError, HttpError, InternalServerError, Mimes, HttpStatus } from '''@dooboostore/simple-boot-http-server''';\n\n@Sim\nexport class GlobalErrorHandler {\n\n    @ExceptionHandler({ type: NotFoundError })\n    handleNotFound(rr: RequestResponse, e: NotFoundError) {\n        // Critical: Check if response is already sent\n        if (rr.resIsDone()) {\n            console.error(`Not found error for URL: ${rr.reqUrl}, but response already sent.`, e);\n            return;\n        }\n        \n        rr.resStatusCode(404)\n          .resSetHeader('''Content-Type''', Mimes.ApplicationJson);\n        rr.resEnd(JSON.stringify({ error: '''Resource not found''' }));\n    }\n\n    @ExceptionHandler()\n    async catch(@Inject({situationType: ExceptionHandlerSituationType.ERROR_OBJECT}) e: any, rr: RequestResponse) {\n        console.error(`GlobalAdvice.catch ${rr.reqUrl}`, e);\n\n        // Critical: Prevent ERR_HTTP_HEADERS_SENT error\n        if (rr.resIsDone()) {\n            return;\n        }\n\n        rr.resStatusCode(HttpStatus.InternalServerError);\n        rr.resSetHeader('''Content-Type''', Mimes.ApplicationJson);\n\n        let data = '''''';\n        if (e instanceof HttpError) {\n            rr.resStatusCode(e.status);\n            data = JSON.stringify(e);\n        } else if (e instanceof Error) {\n            const error = new InternalServerError();\n            error.data = { message: e.message };\n            data = JSON.stringify(error);\n        } else {\n            const error = new InternalServerError();\n            error.data = e;\n            data = JSON.stringify(error);\n        }\n        await rr.resEnd(data);\n    }\n}\n\n// Register in HttpServerOption\nconst option = new HttpServerOption({\n    globalAdvice: GlobalErrorHandler,\n    noSuchRouteEndPointMappingThrow: (rr) => new NotFoundError({ message: `No route for ${rr.reqUrl}` }),\n});</code-example>\n\n                <h3 id=\"session-management\">Session Management</h3>\n                <p class=\"content en\">Built-in session management with automatic cookie handling:</p>\n                <p class=\"content ko\">자동 쿠키 처리를 포함한 내장 세션 관리:</p>\n                \n                <code-example title=\"Session Management\" codeClass=\"language-typescript\">import { RequestResponse } from '''@dooboostore/simple-boot-http-server''';\n\n@Sim\n@Router({ path: '''/api/session''' })\nexport class SessionApi {\n\n    @Route({ path: '''/login''' })\n    @POST({ res: { contentType: Mimes.ApplicationJson } })\n    async login(rr: RequestResponse, body: ReqJsonBody) {\n        const session = await rr.reqSession();\n        \n        // Validate user credentials (simplified)\n        if (body.username === '''admin''' && body.password === '''password''') {\n            session.userId = '''user123''';\n            session.username = body.username;\n            session.loginTime = new Date().toISOString();\n            \n            return { success: true, message: '''Logged in successfully''' };\n        } else {\n            rr.resStatusCode(401);\n            return { success: false, message: '''Invalid credentials''' };\n        }\n    }\n\n    @Route({ path: '''/profile''' })\n    @GET({ res: { contentType: Mimes.ApplicationJson } })\n    async getProfile(rr: RequestResponse) {\n        const session = await rr.reqSession();\n        \n        if (!session.userId) {\n            rr.resStatusCode(401);\n            return { error: '''Not authenticated''' };\n        }\n        \n        let visitCount = session.visitCount || 0;\n        visitCount++;\n        session.visitCount = visitCount;\n        \n        return {\n            userId: session.userId,\n            username: session.username,\n            loginTime: session.loginTime,\n            visitCount: visitCount\n        };\n    }\n\n    @Route({ path: '''/logout''' })\n    @POST({ res: { contentType: Mimes.ApplicationJson } })\n    async logout(rr: RequestResponse) {\n        const session = await rr.reqSession();\n        \n        // Clear session data\n        Object.keys(session).forEach(key => delete session[key]);\n        \n        return { success: true, message: '''Logged out successfully''' };\n    }\n}</code-example>\n\n                <h3 id=\"endpoints\">Lifecycle Endpoints</h3>\n                <p class=\"content en\">Hook into different stages of the request lifecycle:</p>\n                <p class=\"content ko\">요청 생명주기의 다양한 단계에 연결하세요:</p>\n                \n                <code-example title=\"Lifecycle Endpoints\" codeClass=\"language-typescript\">import { EndPoint, RequestResponse, SimpleBootHttpServer } from '''@dooboostore/simple-boot-http-server''';\n\n@Sim\nclass RequestLogger implements EndPoint {\n    async endPoint(rr: RequestResponse, app: SimpleBootHttpServer) {\n        console.log(`New request: ${rr.reqMethod()} ${rr.reqUrl} from ${rr.reqRemoteAddress}`);\n    }\n}\n\n@Sim\nclass ConnectionLogger implements EndPoint {\n    async endPoint(rr: RequestResponse, app: SimpleBootHttpServer) {\n        console.log(`Connection closed for ${rr.reqRemoteAddress}`);\n    }\n}\n\n@Sim\nclass ErrorLogger implements EndPoint {\n    async endPoint(rr: RequestResponse, app: SimpleBootHttpServer) {\n        console.log(`Error occurred for ${rr.reqUrl}`);\n    }\n}\n\n// Register endpoints in HttpServerOption\nconst option = new HttpServerOption({\n    requestEndPoints: [RequestLogger],  // Run when request starts\n    closeEndPoints: [ConnectionLogger], // Run when connection closes\n    errorEndPoints: [ErrorLogger]       // Run when error occurs\n});</code-example>\n            </section>\n\n            <!-- Core Concepts -->\n            <section class=\"section\">\n                <h2 id=\"core-concepts\">Core Concepts</h2>\n                <div class=\"concepts-grid\">\n                    <div class=\"concept-item\">\n                        <h4>@Router & @Route</h4>\n                        <p class=\"content en\">Declarative routing system that maps URLs to classes and methods</p>\n                        <p class=\"content ko\">URL을 클래스와 메서드에 매핑하는 선언적 라우팅 시스템</p>\n                    </div>\n                    <div class=\"concept-item\">\n                        <h4>HTTP Method Decorators</h4>\n                        <p class=\"content en\">@GET, @POST, @PUT, @DELETE and other HTTP method decorators</p>\n                        <p class=\"content ko\">@GET, @POST, @PUT, @DELETE 및 기타 HTTP 메서드 데코레이터</p>\n                    </div>\n                    <div class=\"concept-item\">\n                        <h4>RequestResponse</h4>\n                        <p class=\"content en\">Unified object for handling HTTP requests and responses</p>\n                        <p class=\"content ko\">HTTP 요청과 응답을 처리하는 통합 객체</p>\n                    </div>\n                    <div class=\"concept-item\">\n                        <h4>Filters</h4>\n                        <p class=\"content en\">Middleware system for intercepting requests and responses</p>\n                        <p class=\"content ko\">요청과 응답을 가로채는 미들웨어 시스템</p>\n                    </div>\n                    <div class=\"concept-item\">\n                        <h4>Global Exception Handling</h4>\n                        <p class=\"content en\">Centralized error handling with @ExceptionHandler decorators</p>\n                        <p class=\"content ko\">@ExceptionHandler 데코레이터를 사용한 중앙집중식 오류 처리</p>\n                    </div>\n                    <div class=\"concept-item\">\n                        <h4>Session Management</h4>\n                        <p class=\"content en\">Built-in session handling with automatic cookie management</p>\n                        <p class=\"content ko\">자동 쿠키 관리를 포함한 내장 세션 처리</p>\n                    </div>\n                </div>\n            </section>\n        </div>\n    </div>\n</div>");

